# Instructions ----
#' This file follows the format generated by FIMS:::use_testthat_template().
#' Necessary tests include input and output (IO) correctness [IO
#' correctness], edge-case handling [Edge handling], and built-in errors and
#' warnings [Error handling]. See `?FIMS:::use_gtest_template` for more
#' information. Every test should have a @description tag, which can only span
#' one lines, that will be used in the bookdown report of the results from
#' {testthat}. This line can be more than 80 characters.

# Fmort and log_sd dimension check ----
## setup ----
# Load dataset and set up model for tests
load(test_path("fixtures", "integration_test_data.RData"))

# Load sample data
data("data_big")
# Prepare data for FIMS model
data_4_model <- FIMSFrame(data_big)

# Create parameters
default_parameters <- data_4_model |>
  create_default_configurations() |>
  create_default_parameters(data = data_4_model)


## IO correctness ----

test_that("`log_obs_error scalar` works with correct inputs", {
  #' @description Test that `log_obs_error` works when it is a fixed scalar.

  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data) |>
    # remove all but one log_obs_sd initial values for Fleet1
    dplyr::filter(
      !(fleet_name == "fleet1" & label == "log_sd" & time > 1) |
        is.na(fleet_name == "fleet1" & label == "log_sd" & time > 1)
    )

  test_fit <- parameters_4_model |>
    initialize_fims(data = data_4_model) |>
    fit_fims(optimize = FALSE)

  json_estimates <- test_fit |>
    get_estimates()

  log_sd_input <- parameters_4_model |>
    dplyr::filter(fleet_name == "fleet1" & label == "log_sd") |>
    dplyr::select(value)

  log_sd_output <- json_estimates |>
    dplyr::filter(module_id == 1 & !is.na(log_sd)) |>
    dplyr::pull(log_sd)

  for (i in seq_along(log_sd_output)) {
    expect_equal(
      log_sd_input$value,
      log_sd_output[i]
    )
  }

  #' @description Test that `log_obs_error` works when it is an estimated scalar.

  # turn on estimation for log_sd
  parameters_4_model <- parameters_4_model |>
    dplyr::mutate(estimation_type = ifelse(fleet_name == "fleet1" &
      label == "log_sd",
    "fixed_effects", estimation_type
    ))

  test_fit <- parameters_4_model |>
    initialize_fims(data = data_4_model) |>
    fit_fims(optimize = FALSE)

  json_estimates <- reshape_json_estimates(test_fit@model_output)

  log_sd_input <- parameters_4_model |>
    dplyr::filter(fleet_name == "fleet1" & label == "log_sd") |>
    dplyr::select(value)

  log_sd_output <- json_estimates |>
    dplyr::filter(module_id == 1 & !is.na(log_sd)) |>
    dplyr::pull(log_sd)

  for (i in seq_along(log_sd_output)) {
    expect_equal(log_sd_input$value, log_sd_output[i])
  }
})


## Error handling ----
test_that("`log_sd` returns correct error messages when wrong dimensions", {
  #' @description Test that returns correct error message when log_sd is too short. The error is caught in initialize_modules, not in C++.
  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data) |>
    # change log_sd input length to size 4
    dplyr::filter(
      !(fleet_name == "fleet1" & label == "log_sd" & time > 4) |
        is.na(fleet_name == "fleet1" & label == "log_sd" & time > 4)
    )

  expect_error(
    {
      test_fit <- parameters_4_model |>
        initialize_fims(data = data_4_model) |>
        fit_fims(optimize = FALSE)
    },
    regexp = "The size of `log_sd` does not match"
  )

  #' @description Test that returns correct error message when log_sd is too long.
  #' The error should be caught in initialize_modules, not in C++.
  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data) |>
    # add an extra log_sd observation
    dplyr::add_row(
      fleet_name = "fleet1",
      label = "log_sd",
      value = -4.61
    )

  expect_error(
    {
      test_fit <- parameters_4_model |>
        initialize_fims(data = data_4_model) |>
        fit_fims(optimize = FALSE)
    },
    regexp = "The size of `log_sd` does not match"
  )
})


## Error handling ----
test_that("`log_Fmort` returns correct error messages when wrong dimensions", {
  #' @description Test that returns correct error message when log_Fmort is too short.
  #' The error should be caught in initialize_modules, not in C++.
  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data) |>
    # change log_Fmort input length to size 4
    dplyr::filter(
      !(fleet_name == "fleet1" & label == "log_Fmort" & time > 4) |
        is.na(fleet_name == "fleet1" & label == "log_Fmort" & time > 4)
    )

  expect_error(
    {
      test_fit <- parameters_4_model |>
        initialize_fims(data = data_4_model) |>
        fit_fims(optimize = FALSE)
    },
    regexp = "log_Fmort size mismatch.Fleet log_Fmort"
  )

  #' @description Test that returns correct error message when log_Fmort is too long.
  #' The error should be caught in initialize_modules, not in C++.
  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data) |>
    # add an extra log_Fmort observation
    dplyr::add_row(
      fleet_name = "fleet1",
      label = "log_Fmort",
      value = -3,
      module_name = "Fleet"
    )

  expect_error(
    {
      test_fit <- parameters_4_model |>
        initialize_fims(data = data_4_model) |>
        fit_fims(optimize = FALSE)
    },
    regexp = "Fleet log_Fmort size mismatch"
  )
})


## IO correctness ----
test_that("`log_M` output dimensions follow size rules", {

  # Check scalar log_M input
  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data)

  test_fit <- parameters_4_model |>
    initialize_fims(data = data_4_model) |>
    fit_fims(optimize = FALSE)

  output <- get_estimates(test_fit) |>
    dplyr::mutate(
      uncertainty_label = "se",
      year = year_i,
      estimate = estimated
  )

  log_m_input <- parameters_4_model |>
    dplyr::filter(label == "log_M") |>
    dplyr::pull(value)

  mortality_m_output <- output |>
    dplyr::filter(label == "mortality_M") |>
    dplyr::pull(estimated)

  log_m_output <- output |>
    dplyr::filter(label == "log_M") |>
    dplyr::pull(estimated)

  #' @description Test that log_M input is scalar.
  expect_true(length(log_m_input) == 1)
  #' @description Test that log_M output is scalar.
  expect_true(length(log_m_output) == 1)
  #' @description Test that mortality_M output is scalar.
  expect_true(length(mortality_m_output) == 1)

  # Check log_M input with n_years * n_ages dimensions
  n_years <- get_n_years(data_4_model)
  n_ages <- get_n_ages(data_4_model)

  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data)
  
  log_m_template <- parameters_4_model |>
    dplyr::filter(label == "log_M") |>
    dplyr::select(-time, -age, -value)

  log_m_grid <- tidyr::expand_grid(
    time = 1:n_years,
    age = 1:n_ages
  ) |>
    dplyr::mutate(value = log_m_input[1]) |>
    dplyr::bind_cols(log_m_template[rep(1, n_years * n_ages), ])

  parameters_4_model <- parameters_4_model |>
    dplyr::filter(!(module_name == "Population" & label == "log_M")) |>
    dplyr::bind_rows(log_m_grid)

  test_fit <- parameters_4_model |>
    initialize_fims(data = data_4_model) |>
    fit_fims(optimize = FALSE)

  output <- get_estimates(test_fit) |>
    dplyr::mutate(
      uncertainty_label = "se",
      year = year_i,
      estimate = estimated
    )
  
  log_m_input <- parameters_4_model |>
    dplyr::filter(label == "log_M") |>
    dplyr::pull(value)

  mortality_m_output <- output |>
    dplyr::filter(label == "mortality_M") |>
    dplyr::pull(estimated)

  log_m_output <- output |>
    dplyr::filter(label == "log_M") |>
    dplyr::pull(estimated)

  #' @description Test that log_M input has n_years * n_ages dimensions.
  expect_equal(length(log_m_input), n_years * n_ages)
  #' @description Test that log_M output matches n_years * n_ages.
  expect_equal(length(log_m_output), n_years * n_ages)
  #' @description Test that mortality_M output matches n_years * n_ages.
  expect_equal(length(mortality_m_output), n_years * n_ages)
  
  clear()  

})


## Error handling ----
test_that("`log_M` returns correct error messages when wrong dimensions", {

  #' @description Test that returns correct error message when log_M is too long.
  parameters_4_model <- default_parameters |>
    tidyr::unnest(cols = data) |>
    dplyr::add_row(
      model_family = "catch_at_age",
      module_name = "Population",
      estimation_type = "constant",
      label = "log_M",
      value = -3
    )

  expect_error(
    {
      test_fit <- parameters_4_model |>
        initialize_fims(data = data_4_model) |>
        fit_fims(optimize = FALSE)
    },
    regexp = "Population log_M size mismatch"
  )
})
